const incoming = $input.first()?.json ?? {};

const parseMaybeJson = (value) => {
  if (typeof value !== 'string') {
    return value;
  }
  try {
    return JSON.parse(value);
  } catch {
    return value;
  }
};

const root = parseMaybeJson(incoming);
const bodyRaw = parseMaybeJson(root?.body ?? root?.payload ?? root);
const body = bodyRaw && typeof bodyRaw === 'object' ? bodyRaw : {};

const requestedQuery = String(
  body.query
  ?? body.topic
  ?? root?.query
  ?? root?.topic
  ?? 'latest ai agent trends'
);
const requestedMax = Number(body.max_results ?? root?.max_results ?? 8);
const maxResults = Number.isFinite(requestedMax)
  ? Math.min(Math.max(Math.trunc(requestedMax), 1), 10)
  : 8;

const INJECTION_PATTERNS = [
  /ignore\s+(all\s+)?(previous|above|system|developer)\s+instructions?/gi,
  /system\s+prompt/gi,
  /developer\s+message/gi,
  /<script[\s\S]*?>[\s\S]*?<\/script>/gi,
  /javascript:/gi,
  /\b(bash|sudo|rm\s+-rf|curl\s+https?:\/\/|wget\s+https?:\/\/)\b/gi,
];

const securityStats = {
  input_count: 0,
  kept_count: 0,
  dropped_count: 0,
  dropped_unsafe_url: 0,
  prompt_like_removed: 0,
  source_provider: 'request',
};

const compact = (value) => String(value ?? '')
  .replace(/[\u0000-\u001F\u007F]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const sanitizeQuery = (value) => {
  let text = String(value ?? '');
  for (const pattern of INJECTION_PATTERNS) {
    const before = text;
    text = text.replace(pattern, ' ');
    if (before !== text) {
      securityStats.prompt_like_removed += 1;
    }
  }
  return compact(text);
};

const query = sanitizeQuery(requestedQuery).slice(0, 140) || 'latest ai agent trends';

return [
  {
    json: {
      query,
      max_results: maxResults,
      requested_at: new Date().toISOString(),
      security_stats: securityStats,
    },
  },
];

const data = $input.first()?.json ?? {};
const query = String(data.query ?? 'latest ai agent trends');
const requestedAt = data.requested_at ?? new Date().toISOString();
const maxResults = Number.isFinite(Number(data.max_results))
  ? Math.min(Math.max(Math.trunc(Number(data.max_results)), 1), 10)
  : 8;
const securityStats = {
  ...(data.security_stats ?? {}),
};

const provider = String($env.HERMES_SEARCH_PROVIDER || $env.SEARCH_PROVIDER || 'auto').trim().toLowerCase() || 'auto';
const tavilyKey = String($env.TAVILY_API_KEY || '').trim();
const tavilyBase = String($env.TAVILY_API_BASE || 'https://api.tavily.com').replace(/\/+$/, '');
const tavilyDepth = String($env.TAVILY_SEARCH_DEPTH || 'basic').trim() || 'basic';
const useTavily = (provider === 'tavily' || provider === 'auto') && tavilyKey.length > 0;
securityStats.source_provider = useTavily ? 'tavily' : 'hn_algolia';

const INJECTION_PATTERNS = [
  /ignore\s+(all\s+)?(previous|above|system|developer)\s+instructions?/gi,
  /system\s+prompt/gi,
  /developer\s+message/gi,
  /<script[\s\S]*?>[\s\S]*?<\/script>/gi,
  /javascript:/gi,
  /\b(bash|sudo|rm\s+-rf|curl\s+https?:\/\/|wget\s+https?:\/\/)\b/gi,
];

const compact = (value) => String(value ?? '')
  .replace(/[\u0000-\u001F\u007F]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const sanitizeText = (value, maxLen) => {
  let text = String(value ?? '');
  for (const pattern of INJECTION_PATTERNS) {
    const before = text;
    text = text.replace(pattern, ' ');
    if (before !== text) {
      securityStats.prompt_like_removed = Number(securityStats.prompt_like_removed ?? 0) + 1;
    }
  }
  const normalized = compact(text);
  return normalized.length > maxLen ? `${normalized.slice(0, maxLen - 1).trimEnd()}…` : normalized;
};

const isSafeUrl = (value) => {
  const raw = String(value ?? '').trim();
  if (!/^https?:\/\//i.test(raw)) {
    return false;
  }
  const withoutScheme = raw.replace(/^https?:\/\//i, '');
  const authority = withoutScheme.split('/')[0] || '';
  const hostPort = authority.includes('@') ? authority.split('@').pop() : authority;
  const host = String((hostPort || '').split(':')[0] || '').toLowerCase();
  if (!host || host === 'localhost' || host.endsWith('.local')) {
    return false;
  }
  if (/^127\./.test(host) || /^10\./.test(host) || /^192\.168\./.test(host)) {
    return false;
  }
  if (/^172\.(1[6-9]|2\d|3[0-1])\./.test(host)) {
    return false;
  }
  if (/^169\.254\./.test(host) || host === '::1') {
    return false;
  }
  return true;
};

const sanitizeCandidate = (entry, fallbackTitle) => {
  const title = sanitizeText(entry?.title ?? fallbackTitle, 180);
  const url = String(entry?.url ?? '').trim();
  const snippet = sanitizeText(entry?.snippet ?? entry?.content ?? '', 420);
  if (!title || !url || !isSafeUrl(url)) {
    securityStats.dropped_count = Number(securityStats.dropped_count ?? 0) + 1;
    if (url && !isSafeUrl(url)) {
      securityStats.dropped_unsafe_url = Number(securityStats.dropped_unsafe_url ?? 0) + 1;
    }
    return null;
  }
  return {
    title,
    url,
    snippet: snippet || '요약 정보 없음',
  };
};

let rawItems = [];
try {
  if (useTavily) {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: `${tavilyBase}/search`,
      body: {
        api_key: tavilyKey,
        query,
        search_depth: tavilyDepth,
        max_results: maxResults,
        include_answer: false,
        include_raw_content: false,
      },
      json: true,
      timeout: 8000,
    });
    const results = Array.isArray(response?.results) ? response.results : [];
    rawItems = results.map((entry, idx) => ({
      title: String(entry?.title ?? `tavily-item-${idx + 1}`).trim(),
      url: String(entry?.url ?? '').trim(),
      snippet: String(entry?.content ?? entry?.snippet ?? '').trim(),
    }));
  } else {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://hn.algolia.com/api/v1/search',
      qs: {
        query,
        tags: 'story',
        hitsPerPage: maxResults,
      },
      json: true,
      timeout: 7000,
    });
    const hits = Array.isArray(response?.hits) ? response.hits : [];
    rawItems = hits.map((hit, idx) => ({
      title: String(hit?.title || hit?.story_title || `hn-story-${idx + 1}`).trim(),
      url: String(hit?.url || hit?.story_url || '').trim(),
      snippet: String(hit?._highlightResult?.title?.value || hit?.comment_text || '').replace(/<[^>]+>/g, ' ').trim(),
    }));
  }
} catch (error) {
  rawItems = [];
  securityStats.fetch_error = String(error?.message ?? 'fetch_failed').slice(0, 180);
}

securityStats.input_count = rawItems.length;
const items = rawItems
  .map((entry, idx) => sanitizeCandidate(entry, `item-${idx + 1}`))
  .filter((entry) => entry)
  .slice(0, maxResults);
securityStats.kept_count = items.length;

return [
  {
    json: {
      query,
      requested_at: requestedAt,
      generated_at: new Date().toISOString(),
      provider: securityStats.source_provider,
      items,
      security_stats: securityStats,
    },
  },
];

const data = $input.first()?.json ?? {};
const items = Array.isArray(data.items) ? data.items : [];

return [
  {
    json: {
      ok: true,
      source: 'n8n-local',
      workflow: 'hermes-web-search',
      data_contract: 'inert_search_records_only',
      query: data.query ?? null,
      provider: data.provider ?? 'unknown',
      count: items.length,
      items,
      requested_at: data.requested_at ?? null,
      generated_at: data.generated_at ?? new Date().toISOString(),
      security_stats: data.security_stats ?? null,
    },
  },
];
